const roadmap = JSON.parse(FILE_CONTENT);

// Quality Gate checks
const issues = [];

for (const phase of roadmap.phases) {
  for (const step of phase.steps) {
    const sid = step.step_id;

    // Step ID format check
    if (!/^\d{2}-\d{2}$/.test(sid)) {
      issues.push(`HIGH: Step ID ${sid} doesn't match NN-NN format`);
    }

    // AC referencing private methods
    for (const ac of step.acceptance_criteria || []) {
      if (ac.includes('_method') || ac.includes('._')) {
        issues.push(`HIGH: AC in ${sid} references private method: ${ac.substring(0, 60)}`);
      }
    }

    // Decomposition ratio
    const files = step.files_to_modify || [];
    if (files.length > 0 && 1 / files.length > 2.5) {
      issues.push(`MED: Step ${sid} decomposition ratio > 2.5`);
    }

    // Distill linkage
    if (!step.test_file && !step.scenario_name) {
      issues.push(`MED: Step ${sid} missing test_file/scenario_name (DISTILL linkage)`);
    }

    // Validation-only (no files)
    if (!files.length) {
      issues.push(`MED: Step ${sid} has no files_to_modify`);
    }

    // Print step summary
    console.log(`${sid}: ${step.name}`);
    console.log(`  files: ${files.join(', ')}`);
    console.log(`  test: ${step.test_file || 'MISSING'} / ${step.scenario_name || 'MISSING'}`);
    console.log(`  deps: ${(step.dependencies || []).join(', ') || 'none'}`);
    console.log(`  ACs: ${(step.acceptance_criteria || []).length}`);
    console.log('');
  }
}

// Check for 3+ identical AC structures
const acStructures = {};
for (const phase of roadmap.phases) {
  for (const step of phase.steps) {
    const key = (step.acceptance_criteria || []).length + '-' + (step.files_to_modify || []).length;
    acStructures[key] = (acStructures[key] || 0) + 1;
  }
}
for (const [key, count] of Object.entries(acStructures)) {
  if (count >= 3) {
    issues.push(`LOW: ${count} steps with identical AC/file structure (${key}) — consider batching`);
  }
}

console.log('--- QUALITY GATE ---');
if (issues.length === 0) {
  console.log('PASS: No quality gate issues found');
} else {
  for (const i of issues) console.log(i);
}
console.log(`\nTotal: ${roadmap.phases.reduce((s, p) => s + p.steps.length, 0)} steps across ${roadmap.phases.length} phases`);

